prompt.string:
Original content: {{ $json.input }}

Target platform: {{ $json.platform }}

Please rewrite this content for the specified platform following the platform rules. Return ONLY the rewritten content, no explanations or prefixes.

parameters.jsCode:
// Collect all rewritten content from Claude nodes
const platformResults = [];

for (let i = 0; i < $input.length; i++) {
  const item = $input[i].json;
  platformResults.push({
    platform: item.platform,
    content: item.content || item.message || JSON.stringify(item)
  });
}

return platformResults.map(r => ({ json: r }));
